class Solution:
    def fallingSquares(self, positions):
        import bisect
        xs = set()
        for left, side in positions:
            xs.add(left)
            xs.add(left + side)
        coords = sorted(xs)
        idx = {x: i for i, x in enumerate(coords)}
        heights = [0] * len(coords)
        ans = []
        best = 0
        for left, side in positions:
            lo = idx[left]
            hi = idx[left + side]
            base = 0
            for i in range(lo, hi):
                if heights[i] > base:
                    base = heights[i]
            top = base + side
            for i in range(lo, hi):
                heights[i] = top
            if top > best:
                best = top
            ans.append(best)
        return ans

