class Solution:
    def fallingSquares(self, positions):
        intervals = []
        ans = []
        best = 0
        for left, side in positions:
            right = left + side
            base = 0
            for (l, r, h) in intervals:
                if l < right and left < r:
                    if h > base:
                        base = h
            top = base + side
            intervals.append((left, right, top))
            if top > best:
                best = top
            ans.append(best)
        return ans

