var fallingSquares = function(positions) {
    const intervals = [];
    const ans = [];
    let best = 0;
    for (const [left, side] of positions) {
        const right = left + side;
        let base = 0;
        for (const [l, r, h] of intervals) {
            if (l < right && left < r) {
                if (h > base) base = h;
            }
        }
        const top = base + side;
        intervals.push([left, right, top]);
        if (top > best) best = top;
        ans.push(best);
    }
    return ans;
};
